import axios from "axios";
import { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { toast } from "react-toastify";
import ConversationSection from "../components/lesson/ConversationSection";
import ListeningSection from "../components/lesson/ListeningSection";
import PhrasesSection from "../components/lesson/PhrasesSection";
import ProgressBar from "../components/lesson/ProgressBar";
import QuizSection from "../components/lesson/QuizSection";
import SentencesSection from "../components/lesson/SentencesSection";
import SpeakingSection from "../components/lesson/SpeakingSection";
import StorySection from "../components/lesson/StorySection";
import VocabSection from "../components/lesson/VocabSection";
import { useProgress } from "../context/ProgressContext";

const TABS = [
  { id: "vocabulary", label: "📚 Vocab", lockedBy: null },
  { id: "phrases", label: "💬 Phrases", lockedBy: "vocabulary" },
  { id: "sentences", label: "✍️ Sentences", lockedBy: "phrases" },
  { id: "quiz", label: "❓ Quiz", lockedBy: "sentences" },
  { id: "story", label: "📖 Story", lockedBy: "quiz" },
  { id: "listening", label: "🎧 Listening", lockedBy: "story" },
  { id: "speaking", label: "🎤 Speaking", lockedBy: "listening" },
  { id: "conversation", label: "🗣️ Conversation", lockedBy: "speaking" },
];

const LessonPage = () => {
  const { levelId, day } = useParams();
  const navigate = useNavigate();
  const {
    fetchLessonProgress,
    markSection,
    currentProgress,
    setCurrentProgress,
  } = useProgress();

  const [lesson, setLesson] = useState(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState("vocabulary");

  const lessonId = `L${levelId}D${day}`;

  useEffect(() => {
    async function load() {
      setLoading(true);
      try {
        const [lessonRes] = await Promise.all([
          axios.get(`/api/lessons/${levelId}/${day}`),
          fetchLessonProgress(lessonId),
        ]);
        setLesson(lessonRes.data);
      } catch {
        toast.error("Failed to load lesson.");
      } finally {
        setLoading(false);
      }
    }
    load();
    return () => setCurrentProgress(null);
  }, [levelId, day]);

  const sections = currentProgress?.completedSections || {};
  const allDone = TABS.every((t) => sections[t.id]);

  async function handleMarkDone(sectionId, quizScore) {
    await markSection(
      lessonId,
      parseInt(levelId),
      parseInt(day),
      sectionId,
      quizScore,
    );
    toast.success(
      `✓ ${sectionId.charAt(0).toUpperCase() + sectionId.slice(1)} completed!`,
    );
    // Auto-advance to next tab
    const idx = TABS.findIndex((t) => t.id === sectionId);
    if (idx < TABS.length - 1) setActiveTab(TABS[idx + 1].id);
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <div className="text-center">
          <div className="text-5xl mb-4 animate-bounce">📚</div>
          <p className="text-slate-500 font-bold text-sm">Loading lesson...</p>
        </div>
      </div>
    );
  }

  if (!lesson)
    return (
      <div className="text-center py-20 text-slate-400">Lesson not found.</div>
    );

  return (
    <div className="space-y-4 w-full max-w-4xl mx-auto px-2 sm:px-4 md:px-6 py-6">
      {/* Header */}
      <div className="flex items-center gap-3 bg-[#221f35] border-b border-gray-700 pb-2 mb-4">
        <button
          onClick={() => navigate("/")}
          className="text-sm text-gray-200 hover:text-blue-900 font-bold flex items-center gap-1 transition-colors"
        >
          ← Back
        </button>
        <div className="flex-1">
          <h1 className="text-xl font-extrabold text-gray-200">
            {lesson.topic}
          </h1>
          <p className="text-xs text-gray-200 font-bold">
            {lesson.levelName} · Day {day}
          </p>
        </div>
        {allDone && (
          <span className="bg-green-100 text-green-700 border border-green-200 text-xs font-extrabold px-3 py-1.5 rounded-full">
            🏆 Completed!
          </span>
        )}
      </div>

      {/* Progress */}
      <ProgressBar completedSections={sections} />

      {/* All done banner */}
      {allDone && (
        <div className="bg-[#221f35] border border-gray-700 rounded-2xl p-6 mb-4 text-center fade-in">
          <div className="text-5xl mb-3">🏆</div>
          <h2 className="font-playfair text-2xl text-gray-200 mb-2">
            Day Complete!
          </h2>
          <p className="text-sm text-gray-200 mb-4">
            You've finished all sections for today!
          </p>
          <div className="flex justify-center gap-3">
            <span className="bg-green-100 text-green-700 border border-green-200 text-xs font-extrabold px-3 py-1.5 rounded-full">
              +50 XP Earned 🎉
            </span>
          </div>
          <button
            onClick={() => {
              navigate(`/lesson/${levelId}/${parseInt(day) + 1}`);
              setActiveTab("vocabulary");
            }}
            className="mt-4 text-sm text-gray-400 font-bold hover:underline"
          >
            Next Day →
          </button>
        </div>
      )}

      {/* Tabs */}
      <div className="bg-[#221f35] border border-gray-700 rounded-2xl p-4 shadow-sm overflow-hidden">
        {/* Tab Nav - horizontal scroll */}
        <div className="flex overflow-x-auto scrollbar-hide border-b border-gray-700">
          {TABS.map((tab) => {
            const isLocked = tab.lockedBy && !sections[tab.lockedBy];
            const isDone = sections[tab.id];
            const isActive = activeTab === tab.id;
            return (
              <button
                key={tab.id}
                disabled={isLocked}
                onClick={() => !isLocked && setActiveTab(tab.id)}
                title={isLocked ? `Complete ${tab.lockedBy} first` : ""}
                className={`flex-shrink-0 px-4 py-3.5 text-xs font-extrabold border-b-2 transition-all duration-200 whitespace-nowrap
                  ${isActive ? " bg-[linear-gradient(135deg,#6366f1,#8b5cf6)] border-[1px solid rgba(34,197,94,.3)" : "border-transparent text-slate-500 hover:text-slate-700"}
                  ${isDone && !isActive ? "text-green-600" : ""}
                  ${isLocked ? "opacity-30 cursor-not-allowed" : "cursor-pointer"}`}
              >
                {tab.label}
                {isDone ? " ✓" : ""}
              </button>
            );
          })}
        </div>

        {/* Tab Content */}
        <div className="p-5">
          {activeTab === "vocabulary" && lesson.vocabulary && (
            <VocabSection
              vocab={lesson.vocabulary}
              onDone={() => handleMarkDone("vocabulary")}
              done={!!sections.vocabulary}
            />
          )}
          {activeTab === "phrases" && lesson.phrases && (
            <PhrasesSection
              phrases={lesson.phrases}
              onDone={() => handleMarkDone("phrases")}
              done={!!sections.phrases}
            />
          )}
          {activeTab === "sentences" && lesson.sentences && (
            <SentencesSection
              sentences={lesson.sentences}
              onDone={() => handleMarkDone("sentences")}
              done={!!sections.sentences}
            />
          )}
          {activeTab === "quiz" && lesson.quiz && (
            <QuizSection
              questions={lesson.quiz}
              onDone={(score) => handleMarkDone("quiz", score)}
              done={!!sections.quiz}
            />
          )}
          {activeTab === "story" && lesson.story && (
            <StorySection
              story={lesson.story}
              onDone={() => handleMarkDone("story")}
              done={!!sections.story}
            />
          )}
          {activeTab === "listening" && lesson.listening && (
            <ListeningSection
              listening={lesson.listening}
              onDone={() => handleMarkDone("listening")}
              done={!!sections.listening}
            />
          )}

          {activeTab === "speaking" && lesson.speaking && (
            <SpeakingSection
              speaking={lesson.speaking}
              onDone={() => handleMarkDone("speaking")}
              done={!!sections.speaking}
            />
          )}
          {activeTab === "conversation" && lesson.conversation && (
            <ConversationSection
              conversation={lesson.conversation}
              onDone={() => handleMarkDone("conversation")}
              done={!!sections.conversation}
            />
          )}
        </div>
      </div>
    </div>
  );
};

export default LessonPage;
